import{_ as n,o as a,c as r,a3 as t}from"./chunks/framework.CjquFG0V.js";const g=JSON.parse('{"title":"105. Commencing Grades Nursing","description":"","frontmatter":{"title":"105. Commencing Grades Nursing","eba":"Mental Health Services 2024-2028","topics":["preliminary"]},"headers":[],"relativePath":"ebas/mental-health/rpn-pen-mho/classification-staffing/105-commencing-grades-nursing.md","filePath":"ebas/mental-health/rpn-pen-mho/classification-staffing/105-commencing-grades-nursing.md"}'),o={name:"ebas/mental-health/rpn-pen-mho/classification-staffing/105-commencing-grades-nursing.md"};function i(s,e,p,c,l,m){return a(),r("div",null,[...e[0]||(e[0]=[t('<h1 id="_105-commencing-grades-nursing" tabindex="-1">105. Commencing Grades Nursing <a class="header-anchor" href="#_105-commencing-grades-nursing" aria-label="Permalink to &quot;105. Commencing Grades Nursing&quot;">​</a></h1><p><strong>105.1</strong> A newly registered nurse shall commence at RPN 2 Year 1 except in the following circumstance:</p><p><strong>(a)</strong> where an Employee has completed either:</p><p><strong>(i)</strong> An undergraduate nurse training program with a major in mental health, an undergraduate psychiatric nurse training program in which case the Employee shall commence at RPN 2 Year 2, or</p><p><strong>(ii)</strong> A post graduate diploma in psychiatric and/or mental health nursing in which case an Employee shall commence at RPN 2 Year 3, or</p><p><strong>(b)</strong> was previously an enrolled nurse who completed an undergraduate course leading to registration as a Registered Nurse, in which case the Employee will commence at the RPN 2 increment immediately above the rate of pay previously applicable to the Employee when employed as an PEN.</p><p><strong>(c)</strong> For the avoidance of doubt, should a PEN 4 translate to an RPN 2 classification, they will be permanently salary maintained at the PEN 4 rate, with wage increases paid as set out in schedule 2.</p><p><strong>105.2</strong> Nothing in this clause affects an Employee&#39;s entitlement on appointment to recognition of previous service for the purpose of the commencement increment as per <a href="/eba/ebas/mental-health/rpn-pen-mho/preliminary/70-definitions-specific-to-section-2.html">clause 70.1</a>.</p><p><strong>105.3</strong> Where an Employee has not actively nursed for a period of five years or more, such Employee&#39;s prior service and experience shall not be taken into account.</p><p><strong>105.4</strong> Re-entry course and supervised experience</p><p><strong>(a)</strong> Where a person is employed during an NMBA required Re-entry Course or period of Supervised Experience, such Employee shall be paid at the rate of an RPN 1/PEN 1.1.</p><p><strong>(b)</strong> For the first 12 months after completion of a Re-entry Course or Supervised Experience, where such course or experience is required by the NMBA, the Employee shall be paid at the rate appropriate to their years of experience, but no higher than RPN 2, Year 3.</p><p><strong>(c)</strong> After completion of 12 months&#39; experience in accordance with clause 105.4(b), a nurse (upon sufficient proof to support a claim for incremental advancement) shall be paid at the rate appropriate to their years of experience.</p>',13)])])}const d=n(o,[["render",i]]);export{g as __pageData,d as default};
